class Stack:
 def __init__(self, max_size):
 self.max_size = max_size
 self.stack = [None] * max_size
 self.top = -1

 def push(self, value):
 if self.is_full():
 print('Stack Overflow!')
 return
 self.top += 1
 self.stack[self.top] = value

 def pop(self):
 if self.is_empty():
 print('Stack Underflow!')
 return None
 value = self.stack[self.top]
 self.top -= 1
 return value

 def peek(self):
 if self.is_empty():
 print('Stack is empty')
 return None
 return self.stack[self.top]

 def is_empty(self):
 return self.top == -1

 def is_full(self):
 return self.top == self.max_size - 1

#include <stdio.h>
#define MAX_SIZE 5

int stack[MAX_SIZE];
int top = -1;

void push(int value) {
 if (top == MAX_SIZE - 1) {
 printf('Stack Overflow!');
 return;
 }
 top++;
 stack[top] = value;
}

int pop() {
 if (top == -1) {
 printf('Stack Underflow!');
 return -1;
 }
 int value = stack[top];
 top--;
 return value;
}

int peek() {
 if (top == -1) {
 printf('Stack is empty');
 return -1;
 }
 return stack[top];
}

int is_empty() {
 return top == -1;
}

int is_full() {
 return top == MAX_SIZE - 1;
}
